record_types.code:
type a_Contact is
   record
      Site : Vector_3;
   end record;

type a_Manifold is
   record
      Objects       : Object.views (1 .. 2);
      Contact       : a_Contact;
   end record;

type ray_Collision is
   record
      near_Object  : Object.view;
      hit_Fraction : Real;
      Normal_world : Vector_3;
      Site_world   : Vector_3;
   end record;

